const upsertMunkiHostStatus = `-- name: UpsertMunkiHostStatus :exec
INSERT INTO munki_host_status (
    host_id,
    version,
    manifest_name,
    success,
    errors,
    warnings,
    problem_installs,
    run_started_at,
    run_ended_at,
    last_seen_at
)
VALUES (
    $1,
    $2,
    $3,
    $4::boolean,
    $5,
    $6,
    $7,
    $8,
    $9,
    now()
)
ON CONFLICT (host_id) DO UPDATE SET
    version = EXCLUDED.version,
    manifest_name = EXCLUDED.manifest_name,
    success = EXCLUDED.success,
    errors = EXCLUDED.errors,
    warnings = EXCLUDED.warnings,
    problem_installs = EXCLUDED.problem_installs,
    run_started_at = EXCLUDED.run_started_at,
    run_ended_at = EXCLUDED.run_ended_at,
    last_seen_at = now(),
    updated_at = now()
`

type UpsertMunkiHostStatusParams struct {
	HostID          int64    `json:"host_id"`
	Version         string   `json:"version"`
	ManifestName    string   `json:"manifest_name"`
	Success         *bool    `json:"success"`
	Errors          []string `json:"errors"`
	Warnings        []string `json:"warnings"`
	ProblemInstalls []string `json:"problem_installs"`
	RunStartedAt    string   `json:"run_started_at"`
	RunEndedAt      string   `json:"run_ended_at"`
}

func (q *Queries) UpsertMunkiHostStatus(ctx context.Context, arg UpsertMunkiHostStatusParams) error {
	_, err := q.db.Exec(ctx, upsertMunkiHostStatus,
		arg.HostID,
		arg.Version,
		arg.ManifestName,
		arg.Success,
		arg.Errors,
		arg.Warnings,
		arg.ProblemInstalls,
		arg.RunStartedAt,
		arg.RunEndedAt,
	)
	return err
}
